import { computed } from 'vue';

import layoutDashboard from 'lucide-static/icons/layout-dashboard.svg?url';
import fileText from 'lucide-static/icons/file-text.svg?url';
import image from 'lucide-static/icons/image.svg?url';
import messageSquare from 'lucide-static/icons/message-square.svg?url';
import palette from 'lucide-static/icons/palette.svg?url';
import puzzle from 'lucide-static/icons/puzzle.svg?url';
import users from 'lucide-static/icons/users.svg?url';
import wrench from 'lucide-static/icons/wrench.svg?url';
import settings from 'lucide-static/icons/settings.svg?url';
import archive from 'lucide-static/icons/archive.svg?url';
import barChart from 'lucide-static/icons/bar-chart.svg?url';

/** Double-quoted CSS url() argument so data: URLs containing `)` are not treated as closing url(). */
function cssUrlValue(href) {
  return `"${String(href).replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"`;
}

/**
 * CSS that replaces select WordPress dashicon pseudo-elements with Lucide SVGs (mask, currentColor).
 * Icon choices align with `app/src/assets/css/partials/dashicons-lucide.css` where those rules exist.
 */
export const returnIconOverrides = computed(() => {
  const overrides = [
    ['dashboard', layoutDashboard],
    ['admin-post', fileText],
    ['admin-media', image],
    ['admin-page', fileText],
    ['admin-comments', messageSquare],
    ['admin-appearance', palette],
    ['admin-plugins', puzzle],
    ['admin-users', users],
    ['admin-tools', wrench],
    ['admin-settings', settings],
    ['archive', archive],
    ['chart-bar', barChart],
  ];

  return overrides
    .map(([dashicon, iconUrl]) => {
      const quoted = cssUrlValue(iconUrl);
      return `
  .dashicons-${dashicon}:before {
	content: '';
	height: 1.2rem;
	width: 1.2rem;
	min-height: 1.2rem;
	min-width: 1.2rem;
  display: block;
	background-color: currentColor;
	-webkit-mask: url(${quoted}) no-repeat center;
	-webkit-mask-size: contain;
	mask: url(${quoted}) no-repeat center;
	mask-size: contain;
	font-size: 1.2rem;
  }
`;
    })
    .join('');
});
